#include <stdio.h>
#include <string.h>
#define MOD 1000000007
#define MAXN 100005

int main() {
    int T, N, Q, i, j, l, r, c, p, q;
    char s[MAXN];
    scanf("%d", &T);
    while (T--) {
        scanf("%d %s", &N, s);
        scanf("%d", &Q);
        while (Q--) {
            scanf("%d %d %d %d", &l, &r, &p, &q);
            if (s[l - 1] == 'A') {
                p = (p - q + MOD) % MOD;
                q = (p + q) % MOD;
            } else {
                p = (p + q) % MOD;
                q = (q - p + MOD) % MOD;
            }
            printf("%d %d\n", p, q);
        }
    }
    return 0;
}

